import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  badgeVariants,
  type HbBadgeShape,
  type HbBadgeSize,
  type HbBadgeType,
} from './badge.variants';

@Component({
  selector: 'hb-badge, [hb-badge]',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'badge'",
  },
  exportAs: 'hbBadge',
})
export class HbBadgeComponent {
  readonly hbType = input<HbBadgeType>('default');
  readonly hbShape = input<HbBadgeShape>('pill');
  readonly hbSize = input<HbBadgeSize>('md');
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() =>
    cn(
      badgeVariants({ type: this.hbType(), shape: this.hbShape(), size: this.hbSize() }),
      this.class(),
    ),
  );
}

import { HbBadgeComponent } from './badge.component';
import { HbOverlayBadgeComponent } from './overlay-badge.component';

export const HbBadgeImports = [HbBadgeComponent, HbOverlayBadgeComponent] as const;

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const badgeVariants = cva(
  cn(
    'inline-flex items-center justify-center gap-1 whitespace-nowrap font-medium tabular-nums',
    'transition-colors [&>ng-icon>svg]:size-[1em]',
    'focus-visible:ring-[3px] focus-visible:ring-ring/50 outline-none',
  ),
  {
    variants: {
      type: {
        default: 'bg-primary text-primary-foreground',
        secondary: 'bg-secondary text-secondary-foreground',
        destructive: 'bg-destructive text-destructive-foreground',
        success: 'bg-success text-success-foreground',
        warning: 'bg-warning text-warning-foreground',
        outline: 'border border-border text-foreground',
      },
      shape: {
        rounded: 'rounded-md',
        pill: 'rounded-full',
        circle: 'aspect-square rounded-full p-0',
        square: 'rounded-none',
      },
      size: {
        xs: 'h-4 min-w-4 px-1 text-[0.625rem]',
        sm: 'h-5 min-w-5 px-1.5 text-xs',
        md: 'h-6 min-w-6 px-2 text-xs',
        lg: 'h-7 min-w-7 px-2.5 text-sm',
        xl: 'h-8 min-w-8 px-3 text-base',
      },
    },
    defaultVariants: { type: 'default', shape: 'pill', size: 'md' },
  },
);

export const overlayBadgePositionVariants = cva('pointer-events-none absolute z-10', {
  variants: {
    position: {
      'top-right': 'top-0 right-0 -translate-y-1/2 translate-x-1/2',
      'top-left': 'top-0 left-0 -translate-x-1/2 -translate-y-1/2',
      'bottom-right': 'right-0 bottom-0 translate-x-1/2 translate-y-1/2',
      'bottom-left': 'bottom-0 left-0 -translate-x-1/2 translate-y-1/2',
    },
  },
  defaultVariants: { position: 'top-right' },
});

export type HbBadgeType = NonNullable<VariantProps<typeof badgeVariants>['type']>;
export type HbBadgeShape = NonNullable<VariantProps<typeof badgeVariants>['shape']>;
export type HbBadgeSize = NonNullable<VariantProps<typeof badgeVariants>['size']>;
export type HbBadgePosition = NonNullable<
  VariantProps<typeof overlayBadgePositionVariants>['position']
>;

export * from './badge.component';
export * from './overlay-badge.component';
export * from './badge.variants';
export * from './badge.imports';

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbBadgeComponent } from './badge.component';
import {
  overlayBadgePositionVariants,
  type HbBadgePosition,
  type HbBadgeSize,
  type HbBadgeType,
} from './badge.variants';

@Component({
  selector: 'hb-overlay-badge',
  imports: [HbBadgeComponent],
  template: `
    <ng-content />
    <span
      hb-badge
      [hbType]="hbType()"
      hbShape="pill"
      [hbSize]="hbSize()"
      [class]="badgeClasses()"
      aria-live="polite"
    >
      @if (!isDot()) {
        {{ hbValue() }}
      }
    </span>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'overlay-badge'",
  },
  exportAs: 'hbOverlayBadge',
})
export class HbOverlayBadgeComponent {
  readonly hbValue = input<string | number | null>(null);
  readonly hbType = input<HbBadgeType>('destructive');
  readonly hbPosition = input<HbBadgePosition>('top-right');
  readonly hbDot = input(false, { transform: booleanAttribute });
  readonly hbSize = input<HbBadgeSize>('sm');
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() => cn('relative inline-flex w-fit', this.class()));

  protected readonly isDot = computed(() => {
    const value = this.hbValue();
    return this.hbDot() || value == null || value === '';
  });

  protected readonly badgeClasses = computed(() =>
    cn(
      overlayBadgePositionVariants({ position: this.hbPosition() }),
      'ring-2 ring-background',
      this.isDot() ? 'size-2.5 min-w-0 p-0' : '',
    ),
  );
}

